@Service
public class MfaService {
    private final UserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;

    public MfaService(UserRepository userRepository, BackupCodeRepository backupCodeRepository) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
    }

    public List<String> generateBackupCodes(String username) {
        List<String> codes = new ArrayList<>();
        userRepository.findByUsername(username).ifPresent(user -> {
            for (int i = 0; i < 5; i++) {
                String code = UUID.randomUUID().toString();
                codes.add(code);
                BackupCode backupCode = new BackupCode();
                backupCode.setCode(code);
                backupCode.setUsed(false);
                backupCode.setUser(user);
                user.getBackupCodes().add(backupCode);
            }
            userRepository.save(user);
        });
        return codes;
    }

    public boolean authenticateWithBackupCode(String username, String code) {
        return backupCodeRepository.findByCodeAndUsedFalse(code).map(backupCode -> {
            if (backupCode.getUser().getUsername().equals(username)) {
                backupCode.setUsed(true);
                backupCodeRepository.save(backupCode);
                return true;
            }
            return false;
        }).orElse(false);
    }
}

@RestController
@RequestMapping("/mfa")
public class MfaController {
    private final MfaService mfaService;

    public MfaController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/enable")
    public ResponseEntity<List<String>> enableMfa(@RequestParam String username) {
        List<String> codes = mfaService.generateBackupCodes(username);
        return ResponseEntity.ok(codes);
    }

    @PostMapping("/authenticate")
    public ResponseEntity<String> authenticateWithBackupCode(@RequestParam String username, @RequestParam String code) {
        boolean success = mfaService.authenticateWithBackupCode(username, code);
        return success ? ResponseEntity.ok("Authenticated") : ResponseEntity.status(HttpStatus.UNAUTHORIZED).body("Invalid or used code");
    }
}